var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"수색조 전 대원, 사격 중지!","JPN":"捜索組の全隊員、射撃中止！","ENG":"Search team, cease fire!","TWN":"搜查組暫停開火！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"여긴 미끼용 드론밖에 없어! 녀석들의 모습이 보이지 않는다!","JPN":"ここはおとり用のドローンしかねえ！　奴らの姿が見当たらないんだ！","ENG":"There's nothing but bait drones here! No eyes on any of them!","TWN":"這裡的無人機都是誘餌！沒看到那些傢伙！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"갑자기 어디서 튀어나올지 몰라! 특히 카운터인 스나이퍼를 주의하면서 사주 경계!","JPN":"いきなりどこから飛び出してくるかしれねえ！　特にカウンターのスナイパーに注意しながら全方位を警戒しろ！","ENG":"You don't know where they'll pop out from! Be especially careful of that Counter sniper!","TWN":"注意周圍，她們很可能會突然從哪裡冒出來！尤其要注意制裁者的狙擊手！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"다른 두 놈보다는 초짜지만, 그 만큼 행동을 예측하기가 어려워!","JPN":"他の二人よりは素人だが、その分行動を予測しづらい！","ENG":"She may be a noob compared to the other two, but that just makes her actions more unpredictable!","TWN":"雖然她比另外二個新，但這也就表示無法用常理來判斷她的下一步！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"으음?","JPN":"むむ？","ENG":"Mm?","TWN":"嗯嗯？"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"대장! 상대 측 함선이 거점 방향으로 이동하고 있습니다!","JPN":"隊長！　相手の艦船が拠点方向へ移動しています！","ENG":"Leader! The opponent's ship is heading straight toward our base!","TWN":"隊長！對方的艦船正往據點的方向移動！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"거리 900… 850… 800…! 빠릅니다! 수송선 치고 너무 빨라요!","JPN":"距離900……850……800……！　速いです！　輸送船にしては速すぎます！","ENG":"Distance is 900... 850... 800...! It's fast! Too fast for a transport aircraft!","TWN":"距離剩900…850… 800…！速度好快！沒見過這麼快的運輸機！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"무장도 없는 수송선으로 돌격을?","JPN":"武装もない輸送船で突撃を？","ENG":"Charging straight in with an aircraft that's not even armed?","TWN":"她們打算用沒有任何武裝的運輸機突襲據點？"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"무슨 판단이지? 포인트를 시궁창에 버릴 생각인가?","JPN":"何を考えているんだ？　ポイントをどぶに捨てる気か？","ENG":"What are they thinking? Are they going to throw all their points away?","TWN":"這是什麼意思？她們要白白浪費點數嗎？"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"흥, 역시 아무것도 모르네요. 바보들.","JPN":"フン、やっぱり何もわかってないんですね。バーカ。","ENG":"Hmph. These idiots really don't know anything.","TWN":"哼，你們這群笨蛋，果然什麼都不知道。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"우리가 왜 굳이 그로니아까지 갔다 왔겠어요? 메롱!","JPN":"私たちが何の理由もなくグロニアに行ってきたと思ってるんですか？　べーっ！","ENG":"Why do you think we went through the trouble of going to Gronia? Bleh!","TWN":"你以為我們為什麼非要去一趟格羅尼亞？ㄌㄩㄝ！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"……설마, 그래서 무장이 없는 수송선을!?","JPN":"……まさか、それで武装のない輸送船を！？","ENG":"...Wait. Is that why they brought an unarmed transport aircraft?!","TWN":"……難道？所以她們才會使用沒有武裝的運輸機！？"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"속공이다! 녀석들은 함선 안에 있다! 함선째로 우리 측 거점을 정면 돌파하려는 거야!!","JPN":"速攻だ！　奴らは艦船の中にいる！　艦船ごと俺らの拠点を正面突破するつもりだ！！","ENG":"It's a fast break! They're inside the ship! They're thinking of charging straight into our base!","TWN":"快攻！她們都在艦船裡！她們打算利用艦船正面迎擊我們的據點！！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"여기는 방어조!","JPN":"こちら、防御組！","ENG":"This is the defense team!","TWN":"這裡是防守組！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"대장님! 저희 쪽에서도 상대 함선을 육안으로 관측하였습니다!","JPN":"隊長！　こちらからも相手の艦船を肉眼で確認しました！","ENG":"Leader! We also got eyes on their ship!","TWN":"隊長！我們這邊也有在盯著對方艦船的動向！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"좋아! 거점에 대기하고 있는 방어조 전원은 함선 갑판으로 이동!","JPN":"よし！　拠点に待機している防御組は全員艦船のデッキに移動！","ENG":"Okay! All defense members on base, head to the deck!","TWN":"非常好！在據點待命的防守組全部登上艦船甲板！"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}}]`);export{e as default};